import React, { useState, useEffect } from 'react';
import axios from 'axios';

function Admin() {
  const [requests, setRequests] = useState([]);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [password, setPassword] = useState('');
  const [editingProject, setEditingProject] = useState(null); 
  const adminPassword = "admin123";

  const fetchData = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setRequests(res.data);
    } catch (err) { console.error("Error:", err); }
  };

  useEffect(() => { if (isLoggedIn) fetchData(); }, [isLoggedIn]);

  const handleLogin = (e) => {
    e.preventDefault();
    if (password === adminPassword) setIsLoggedIn(true);
    else alert("Incorrect Password!");
  };

  const handleUpdate = async (e) => {
    e.preventDefault();
    try {
      await axios.put(`http://localhost:5000/api/update-status/${editingProject._id}`, editingProject);
      alert("✅ Updated Successfully!");
      setEditingProject(null);
      fetchData();
    } catch (err) { alert("❌ Update failed!"); }
  };

  // --- १. मॅजिक बटण लॉजिक: एका क्लिकवर फुल पेमेंट करण्यासाठी ---
  const handleQuickFullPaid = async (req) => {
    if (window.confirm(`Mark ${req.fullName}'s project as Fully Paid?`)) {
      try {
        await axios.put(`http://localhost:5000/api/update-status/${req._id}`, {
          ...req,
          advancePaid: req.totalBudget, // बजेट आणि पेड अमाऊंट सेम करणे
          paymentStatus: "Paid"
        });
        alert("✅ Success: Project is now Fully Paid!");
        fetchData();
      } catch (err) { alert("❌ Failed to update!"); }
    }
  };

  const handleResolveRevision = async (id) => {
    if (window.confirm("Mark this revision as completed?")) {
      try {
        await axios.put(`http://localhost:5000/api/update-status/${id}`, {
          revisionsRequested: "" 
        });
        alert("✅ Revision resolved!");
        fetchData();
      } catch (err) { alert("❌ Operation failed!"); }
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm("Delete this project?")) {
      await axios.delete(`http://localhost:5000/api/delete-request/${id}`);
      fetchData();
    }
  };

  if (!isLoggedIn) {
    return (
      <div className="d-flex justify-content-center align-items-center bg-light" style={{minHeight: '100vh'}}>
        <div className="card shadow border-0 p-4" style={{width: '380px', borderRadius: '15px'}}>
          <h4 className="text-center fw-bold mb-4">Admin Access</h4>
          <form onSubmit={handleLogin}>
            <div className="mb-3">
              <label className="small fw-bold text-muted">PASSWORD</label>
              <input type="password" placeholder="••••••" className="form-control form-control-lg shadow-sm" value={password} onChange={(e) => setPassword(e.target.value)} required />
            </div>
            <button className="btn btn-dark w-100 fw-bold py-2 shadow">Unlock Dashboard</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="container-fluid py-4 px-lg-5 bg-light" style={{minHeight: '100vh'}}>
      <div className="d-flex justify-content-between align-items-center mb-4">
        <div>
          <h2 className="fw-bold m-0 text-dark">Project Management</h2>
          <p className="text-muted small">Real-time control over client requests and payments</p>
        </div>
        <button className="btn btn-outline-danger btn-sm px-4 fw-bold rounded-pill" onClick={() => setIsLoggedIn(false)}>Logout</button>
      </div>

      <div className="card border-0 shadow-sm rounded-4 overflow-hidden">
        <table className="table table-hover mb-0 align-middle text-nowrap">
          <thead className="bg-dark text-white">
            <tr className="small text-uppercase">
              <th className="py-3 ps-4">Client / Service</th>
              <th>Progress</th>
              <th>Financials</th>
              <th>Client Revisions</th>
              <th>Status</th>
              <th className="text-end pe-4">Actions</th>
            </tr>
          </thead>
          <tbody>
            {requests.map((req) => (
              <tr key={req._id}>
                <td className="ps-4">
                  <div className="fw-bold text-dark">{req.fullName}</div>
                  <div className="text-primary small fw-semibold">{req.serviceType}</div>
                </td>
                <td>
                  <div className="d-flex align-items-center gap-2" style={{width: '100px'}}>
                    <div className="progress flex-grow-1" style={{height: '6px', borderRadius: '10px'}}>
                      <div className="progress-bar bg-success" style={{width: `${req.progress}%`}}></div>
                    </div>
                    <span className="small fw-bold">{req.progress}%</span>
                  </div>
                </td>
                <td>
                  <div className="small mb-1">
                    <span className="text-muted">Budget:</span> <b className="text-dark">₹{req.totalBudget}</b><br/>
                    <span className="text-muted">Paid:</span> <b className="text-success">₹{req.advancePaid}</b>
                  </div>
                  {/* २. मार्क फुल्ली पेड बटण - जर पेमेंट बाकी असेल तरच दिसेल */}
                  {req.totalBudget > req.advancePaid && (
                    <button 
                      className="btn btn-outline-success btn-xs py-0 px-2 fw-bold" 
                      style={{fontSize: '10px'}}
                      onClick={() => handleQuickFullPaid(req)}
                    >
                      Mark Full Paid
                    </button>
                  )}
                </td>

                <td style={{maxWidth: '200px', whiteSpace: 'normal'}}>
                  {req.revisionsRequested ? (
                    <div className="bg-warning-subtle p-2 border border-warning rounded">
                      <div className="small text-dark mb-2 fw-semibold">"{req.revisionsRequested}"</div>
                      <button className="btn btn-success btn-sm w-100 py-0 fw-bold" style={{fontSize: '10px'}} onClick={() => handleResolveRevision(req._id)}>DONE</button>
                    </div>
                  ) : <span className="text-muted small">No requests</span>}
                </td>

                <td>
                  <span className={`badge rounded-pill px-3 ${req.status === 'Completed' ? 'bg-success-subtle text-success border' : 'bg-warning-subtle text-warning border'}`}>
                    {req.status}
                  </span>
                </td>
                <td className="text-end pe-4">
                  <button className="btn btn-sm btn-light border me-2 shadow-sm" onClick={() => setEditingProject(req)}>Edit</button>
                  <button className="btn btn-sm btn-outline-danger shadow-sm" onClick={() => handleDelete(req._id)}>Delete</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* --- EDIT MODAL --- */}
      {editingProject && (
        <div className="modal show d-block" style={{backgroundColor: 'rgba(0,0,0,0.6)'}}>
          <div className="modal-dialog modal-dialog-centered">
            <div className="modal-content border-0 rounded-4">
              <div className="modal-header border-0 bg-light rounded-top-4">
                <h5 className="fw-bold m-0">Edit Project</h5>
                <button type="button" className="btn-close" onClick={() => setEditingProject(null)}></button>
              </div>
              <form onSubmit={handleUpdate}>
                <div className="modal-body py-4">
                  <div className="row g-3">
                    <div className="col-6">
                      <label className="small fw-bold">Total Budget</label>
                      <input type="number" className="form-control" value={editingProject.totalBudget} onChange={(e) => setEditingProject({...editingProject, totalBudget: e.target.value})} />
                    </div>
                    <div className="col-6">
                      <label className="small fw-bold">Advance Paid</label>
                      <input type="number" className="form-control" value={editingProject.advancePaid} onChange={(e) => setEditingProject({...editingProject, advancePaid: e.target.value})} />
                    </div>
                    <div className="col-6">
                      <label className="small fw-bold">Progress (%)</label>
                      <input type="number" className="form-control" value={editingProject.progress} onChange={(e) => setEditingProject({...editingProject, progress: e.target.value})} />
                    </div>
                    <div className="col-6">
                      <label className="small fw-bold">Status</label>
                      <select className="form-select" value={editingProject.status} onChange={(e) => setEditingProject({...editingProject, status: e.target.value})}>
                        <option value="Pending">Pending</option>
                        <option value="In Progress">In Progress</option>
                        <option value="Completed">Completed</option>
                      </select>
                    </div>
                  </div>
                </div>
                <div className="modal-footer border-0 bg-light rounded-bottom-4">
                  <button type="submit" className="btn btn-dark w-100 fw-bold shadow">Save Changes</button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default Admin;
